head.script:
scwin.arrRtnVal = [];
scwin.gv_strExistTF = "";
scwin.arrParent = [];
scwin.gv_userClsCd = "";
scwin.gv_clntNo = "";
scwin.gv_clntNm = "";
scwin.dateStr = "";
scwin.dateTime = "";
scwin.rowFlag = "";
scwin.btnFlag = "";

scwin.hid_odrNo1 = "";
scwin.hid_odrNo2 = "";
scwin.hid_seq1 = 0;
scwin.hid_seq2 = 0;
scwin.hid_crryinCrryoutCls1 = "";
scwin.hid_crryinCrryoutCls2 = "";
scwin.hid_crryinoutCls1 = "";
scwin.hid_crryinoutCls2 = "";
scwin.hid_sndClsCd1 = "";
scwin.hid_sndClsCd2 = "";
scwin.hid_transCntSht1 = "";
scwin.hid_transCntSht2 = "";
scwin.hid_startPoint1 = "";
scwin.hid_rcv1 = "";
scwin.hid_rcv2 = "";
scwin.hid_crryinoutDtmMint1 = "";
scwin.hid_crryinoutDtmMint2 = "";
scwin.hid_transDstFromWrkPlCd1 = "";
scwin.hid_transDstToWrkPlCd2 = "";
scwin.hid_temperCls2 = "";
scwin.hid_sizTyp1 = "";
scwin.hid_sizTyp2 = "";
scwin.hid_transWrkIndictNo1 = "";
scwin.hid_transWrkIndictNo2 = "";

scwin.EDI_SND_CLS_CD_SND_WAIT = "0";
scwin.EDI_SND_CLS_CD_SND_COMPLETE = "1";
scwin.EDI_SND_CLS_CD_LATER_SND = "3";
scwin.EDI_SND_CLS_CD_IMPITEM_WARN = "4";
scwin.EDI_DOC_STS_CLS_ORIG = "9";
scwin.EDI_DOC_STS_CLS_CHG = "4";
scwin.EDI_GRPCD_TM = "T";
scwin.EDI_GRPCD_LG = "L";
scwin.EDI_GRPCD_KYUNGIN_ICD = "K";
scwin.EDI_FULL_EMPTY_CLS_FULL = "5";
scwin.EDI_TEMPER_CLS_DRY = "DRY";
scwin.EDI_TEMPER_CLS_CEL = "CEL";
scwin.WRK_PL_CLS_CD_PORT = "P";
scwin.WRK_STP_CD_RAILROAD = "R";
scwin.YN_YES = "Y";

scwin.onpageload = async function() {
    scwin.gv_userClsCd = $c.ses.getUserClsCd();
    scwin.gv_clntNo = $c.ses.getClntNo();
    scwin.gv_clntNm = $c.ses.getClntNm();
    scwin.dateStr = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    scwin.dateTime = scwin.f_getNowTime();
    scwin.arrParent = $c.data.getParameter();

    scwin.f_onLoad();
};

scwin.f_onLoad = async function() {
    ds_resultsCopinoOut.removeAll();
    ds_resultsCopinoIn.removeAll();

    scwin.f_defaultValue();

    scwin.f_disableObjects();
    scwin.f_create();
};

scwin.f_defaultValue = async function() {
    scwin.hid_odrNo1 = "9999999999999";
    scwin.hid_odrNo2 = "9999999999999";

    scwin.hid_seq1 = 0;
    scwin.hid_seq2 = 0;

    scwin.hid_crryinCrryoutCls1 = "1";
    scwin.hid_crryinCrryoutCls2 = "2";

    scwin.hid_crryinoutCls1 = "1";
    scwin.hid_crryinoutCls2 = "2";

    ica_crryinoutDt1.setValue("");
    ed_crryinoutHh1.setValue("");
    ica_crryinoutDt2.setValue("");
    ed_crryinoutHh2.setValue("");

    ica_crryinoutDt1.setValue(scwin.dateStr);
    ed_crryinoutHh1.setValue(scwin.f_getNowTime());
    ica_crryinoutDt2.setValue(scwin.dateStr);
    ed_crryinoutHh2.setValue(scwin.f_getNowTime());

    ica_vsslArrvlportYr1.setValue("");
    ica_vsslArrvlportYr2.setValue("");

    let strCurYear = scwin.dateStr.substring(0, 4);
    ica_vsslArrvlportYr1.setValue(strCurYear);
    ica_vsslArrvlportYr2.setValue(strCurYear);

    scwin.hid_sndClsCd1 = scwin.EDI_SND_CLS_CD_SND_WAIT;
    scwin.hid_sndClsCd2 = scwin.EDI_SND_CLS_CD_SND_WAIT;

    scwin.hid_transCntSht1 = "3";
    scwin.hid_transCntSht2 = "3";
};

scwin.f_create = async function() {
    ds_resultsCopinoOut.removeAll();
    ds_resultsCopinoIn.removeAll();

    scwin.f_FieldClear();
    scwin.f_defaultValue();

    $c.gus.cfEnableBtnOnly([btnCreate]);
    $c.gus.cfEnableBtnOnly([btnSave]);

    // TODO: chk_crryOutCopino, chk_crryInCopino checked 설정
    scwin.f_switchTransYn(1);
    scwin.f_switchTransYn(2);

    scwin.f_disableObjects();
};

scwin.f_getNowTime = async function() {
    let now = new Date();
    let hour = now.getHours();
    let min = now.getMinutes();
    if (hour <= 9) hour = "0" + hour;
    if (min <= 9) min = "0" + min;
    return hour + "" + min;
};

scwin.f_Retrieve = async function(gubun) {
    let vehclIdCardNoVal = ed_vehclNoFrtcarNo1.getValue();
    let cntrNoVal = ed_cntrNo.getValue();

    if ((vehclIdCardNoVal == null || vehclIdCardNoVal == "") &&
        (cntrNoVal == null || cntrNoVal == "")) {
        await $c.gus.cfAlertMsg("조회시 차량 ID와 CNTR_NO 중 둘중에 하나 기입해야 합니다.");
        return false;
    }

    if (vehclIdCardNoVal != null && vehclIdCardNoVal != "") {
        if (vehclIdCardNoVal.length != 8) {
            await $c.gus.cfAlertMsg("조회시 차량 ID는  8자리를  기입해야 합니다.");
            return false;
        }
    }
    if (cntrNoVal != null && cntrNoVal != "") {
        if (cntrNoVal.length != 11) {
            await $c.gus.cfAlertMsg("조회시 컨테이너는 번호는 11자리를  기입해야 합니다.");
            return false;
        }
    }

    ds_search.set("vehclIdCardNo", vehclIdCardNoVal);
    ds_search.set("cntrNo", cntrNoVal);

    if (gubun == null || gubun == "" || gubun == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoIn.removeAll();
        scwin.btnFlag = "";
        scwin.rowFlag = "";
        await $c.sbm.execute(sbm_retrieve);
    } else {
        // TODO: chk_crryInCopino, chk_crryOutCopino checked 상태 확인 후 분기
        // 원본 로직: checked false 시 ds2 clear 후 copy + retrieve2
        await $c.sbm.execute(sbm_retrieve2);
    }

    let outCount = ds_resultsCopinoOut.getRowCount();
    let inCount = ds_resultsCopinoIn.getRowCount();

    if (outCount == 0 && inCount > 0) {
        ds_resultsCopinoOut.removeAll();
        ica_crryinoutDt1.setValue("");
        ed_crryinoutHh1.setValue("");
        ica_vsslArrvlportYr1.setValue("");
        scwin.f_switchTransYn(1);
        scwin.f_switchTransYn(2);
    } else if (inCount == 0 && outCount > 0) {
        ds_resultsCopinoIn.removeAll();
        ica_crryinoutDt2.setValue("");
        ed_crryinoutHh2.setValue("");
        ica_vsslArrvlportYr2.setValue("");
        scwin.f_switchTransYn(1);
        scwin.f_switchTransYn(2);
    } else if (inCount == 0 && outCount == 0) {
        ds_resultsCopinoOut.removeAll();
        ds_resultsCopinoIn.removeAll();
        scwin.f_switchTransYn(1);
        scwin.f_switchTransYn(2);
    } else if (inCount > 0 && outCount > 0) {
        scwin.f_switchTransYn(1);
        scwin.f_switchTransYn(2);
        scwin.f_disableObjects();
    }

    if (acb_temperCls2.getValue() == "DRY") {
        $c.gus.cfDisableObjects([ed_frzTemper2]);
    } else {
        $c.gus.cfEnableObjects([ed_frzTemper2]);
    }

    let v_expimpClsCd1 = acb_expimpClsCd1.getValue();
    let v_expimpClsCd2 = acb_expimpClsCd2.getValue();

    if (v_expimpClsCd1 == "E") {
        $c.gus.cfDisableObjects([ed_blNo1]);
    } else if (v_expimpClsCd1 == "I") {
        $c.gus.cfDisableObjects([ed_bookingNo1]);
    }

    if (v_expimpClsCd2 == "E") {
        $c.gus.cfDisableObjects([ed_blNo2]);
    } else if (v_expimpClsCd2 == "I") {
        $c.gus.cfDisableObjects([ed_bookingNo2]);
    }

    let v_fullEmptyClsCd1 = acb_fullEmptyClsCd1.getValue();
    let v_fullEmptyClsCd2 = acb_fullEmptyClsCd2.getValue();

    if (v_fullEmptyClsCd1 == "4") {
        $c.gus.cfDisableObjects([ed_sealNo1]);
    } else if (v_fullEmptyClsCd1 == "5") {
        $c.gus.cfEnableObjects([ed_sealNo1]);
    }

    if (v_fullEmptyClsCd2 == "4") {
        $c.gus.cfDisableObjects([ed_sealNo2]);
    } else if (v_fullEmptyClsCd2 == "5") {
        $c.gus.cfEnableObjects([ed_sealNo2]);
    }
};

scwin.f_disableObjects = async function() {
    $c.gus.cfDisableObjects([ed_transDstFromNm1, ed_transDstToNm1, txt_mchtNm1, ed_transDstToNm2, ed_suitCoTransCoNm1, ed_suitCoTransCoNm2, ed_transDstFromNm2, ed_dchrPortNm2, txt_mchtNm2]);
};

scwin.f_validate = async function() {
    if (ds_resultsCopinoOut.getRowCount() > 0 && !$c.gus.cfIsNull(ds_resultsCopinoOut.getCellData(0, "transDstFrom"))) {
        if (!(await $c.gus.cfValidate([tb_crryOutCopino]))) {
            return false;
        }

        if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) {
            scwin.hid_startPoint1 = ed_transDstFrom1.getValue();

            if (ed_transDstFrom1.getValue() == "6P42") {
                ed_mchtCd1.setMandatory(true);
                ed_cntrNo1.setMandatory(false);
                ed_cntrNo1.setValue("");
            } else if (ed_transDstFrom1.getValue() == "6P14" || ed_transDstFrom1.getValue() == "6P12") {
                if (acb_fullEmptyClsCd2.getValue() == "4") {
                    ed_cntrNo1.setMandatory(true);
                    ed_cntrNo1.setValue("ZZZZ1234567");
                }
            } else {
                ed_cntrNo1.setMandatory(true);
            }

            if (ed_transDstFrom1.getValue() == "6P13") {
                acb_chassisPosInfo1.setMandatory(true);
            } else {
                acb_chassisPosInfo1.setMandatory(false);
            }
        }

        if (ed_transDstFrom1.getValue().substring(1, 2) == scwin.WRK_PL_CLS_CD_PORT) {
            ed_shpCoCd1.setMandatory(true);
        }

        if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) {
            scwin.hid_rcv1 = ed_transDstFrom1.getValue();
        } else {
            scwin.hid_rcv1 = "";
        }

        if (ed_tmlVsslPortcnt1.getValue().length == 5) {
            ds_resultsCopinoOut.setCellData(0, "tmlVsslPortcnt", ed_tmlVsslPortcnt1.getValue().substring(0, 3) + " " + ed_tmlVsslPortcnt1.getValue().substring(3, 5));
        }

        scwin.hid_crryinoutDtmMint1 = ica_crryinoutDt1.getValue() + ed_crryinoutHh1.getValue();

        if (ds_resultsCopinoOut.getCellData(0, "preInfoGrpClsCd") == scwin.EDI_GRPCD_TM
            && ds_resultsCopinoOut.getCellData(0, "vehclIdCardNo") == "") {
            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
            return false;
        }

        // TODO: chk_crryOutCopino checked 시 cfCopyDataSet 처리
        let v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        $c.gus.cfCopyDataSet(ds_resultsCopinoOut, ds_resultsCopinoOut2, v_features);

        let sizTyp1Val = ed_sizTyp1.getValue();
        let validSizTypes = ["2210","2270","2232","2251","2264","4310","4370","4332","4351","4364","4510","9510","4532","4350","2250"];
        if (validSizTypes.indexOf(sizTyp1Val) == -1) {
            await $c.win.alert("SIZ/TYPE을 정확하게 입력하세요!!!");
            ed_sizTyp1.setFocus();
            return false;
        }
    }

    if (ds_resultsCopinoIn.getRowCount() > 0 && !$c.gus.cfIsNull(ds_resultsCopinoIn.getCellData(0, "transDstTo"))) {
        if (!(await $c.gus.cfValidate([tb_crryInCopino]))) {
            return false;
        }

        if (!$c.gus.cfIsNull(ed_transDstTo2.getValue())) {
            scwin.hid_rcv2 = ed_transDstTo2.getValue();
        } else {
            scwin.hid_rcv2 = "";
        }

        if (ed_tmlVsslPortcnt2.getValue().length == 5) {
            ds_resultsCopinoIn.setCellData(0, "tmlVsslPortcnt", ed_tmlVsslPortcnt2.getValue().substring(0, 3) + " " + ed_tmlVsslPortcnt2.getValue().substring(3, 5));
        }

        scwin.hid_crryinoutDtmMint2 = ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue();

        if (ds_resultsCopinoIn.getCellData(0, "fullEmptyClsCd") == scwin.EDI_FULL_EMPTY_CLS_FULL
            && (ds_resultsCopinoIn.getCellData(0, "totWt") == 0 || ds_resultsCopinoIn.getCellData(0, "totWt") == "")) {
            await $c.gus.cfAlertMsg("[E/F] 구분이 FULL 일때 [WEIGHT]는 필수입니다");
            return false;
        }

        if (ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == scwin.EDI_GRPCD_TM
            && ds_resultsCopinoIn.getCellData(0, "vehclIdCardNo") == "") {
            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
            return false;
        }

        if (ds_resultsCopinoIn.getCellData(0, "preInfoGrpClsCd") == scwin.EDI_GRPCD_TM
            && ds_resultsCopinoIn.getCellData(0, "tmlVsslPortcnt") == "") {
            await $c.gus.cfAlertMsg("[사전정보그룹구분]이 터미널 일때 [모선/항차]는 필수입니다");
            return false;
        }

        // TODO: chk_crryInCopino checked 시 cfCopyDataSet 처리
        let v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
        $c.gus.cfCopyDataSet(ds_resultsCopinoIn, ds_resultsCopinoIn2, v_features);

        let sizTyp2Val = ed_sizTyp2.getValue();
        let validSizTypes = ["2210","2270","2232","2251","2264","4310","4370","4332","4351","4364","4510","9510","4532","4350","2250"];
        if (validSizTypes.indexOf(sizTyp2Val) == -1) {
            await $c.win.alert("SIZ/TYPE을 정확하게 입력하세요!!!");
            ed_sizTyp2.setFocus();
            return false;
        }
    }

    if (ed_sizTyp2.getValue() == "2232" || ed_sizTyp2.getValue() == "4332" || ed_sizTyp2.getValue() == "4532") {
        if (ed_frzTemper2.getValue() == "") {
            await $c.win.alert("냉동컨테이너 입력시 온도는 필수 입력 사항입니다.");
            ed_frzTemper2.setFocus();
            return false;
        }
    }

    return true;
};

scwin.f_save = async function() {
    if ($c.gus.cfIsNull(ds_resultsCopinoOut.getCellData(0, "transDstFrom")) && $c.gus.cfIsNull(ds_resultsCopinoIn.getCellData(0, "transDstTo"))) {
        await $c.gus.cfAlertMsg("저장할 데이터가 없습니다");
        return;
    }

    if (!(await scwin.f_validate())) {
        return;
    }

    if (ds_resultsCopinoOut2.getRowCount() > 0) {
        if ($c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "cls"))) {
            ds_resultsCopinoOut2.setCellData(0, "cls", "T");
        }
        if ($c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "snd"))) {
            ds_resultsCopinoOut2.setCellData(0, "snd", "DBE");
        }
        if ($c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "rcv"))) {
            ds_resultsCopinoOut2.setCellData(0, "rcv", "DBE");
        }
        if ($c.gus.cfIsNull(ds_resultsCopinoOut2.getCellData(0, "sndClsCd"))) {
            ds_resultsCopinoOut2.setCellData(0, "sndClsCd", scwin.EDI_SND_CLS_CD_SND_WAIT);
        }
        if (ds_resultsCopinoOut2.getCellData(0, "docStsCls") == "") {
            ds_resultsCopinoOut2.setCellData(0, "docStsCls", scwin.EDI_DOC_STS_CLS_ORIG);
        }
        if (ds_resultsCopinoOut2.getCellData(0, "sndClsCd") == scwin.EDI_SND_CLS_CD_SND_COMPLETE) {
            ds_resultsCopinoOut2.setCellData(0, "docStsCls", scwin.EDI_DOC_STS_CLS_CHG);
        }

        scwin.hid_crryinoutDtmMint1 = ica_crryinoutDt1.getValue() + ed_crryinoutHh1.getValue();
        ds_resultsCopinoOut2.setCellData(0, "setGauceJobType", 2);
        ds_resultsCopinoOut2.setCellData(0, "emcTransCoId", "DBEXC050");
        ds_resultsCopinoOut2.setCellData(0, "dpctTransCoId", "DBEXC050");
    }

    if (ds_resultsCopinoIn2.getRowCount() > 0) {
        if ($c.gus.cfIsNull(ds_resultsCopinoIn2.getCellData(0, "snd"))) {
            ds_resultsCopinoIn2.setCellData(0, "snd", "DBE");
        }
        if ($c.gus.cfIsNull(ds_resultsCopinoIn2.getCellData(0, "sndClsCd"))) {
            ds_resultsCopinoIn2.setCellData(0, "sndClsCd", scwin.EDI_SND_CLS_CD_SND_WAIT);
        }
        if (ds_resultsCopinoIn2.getCellData(0, "docStsCls") == "") {
            ds_resultsCopinoIn2.setCellData(0, "docStsCls", scwin.EDI_DOC_STS_CLS_ORIG);
        }
        if (ds_resultsCopinoIn2.getCellData(0, "sndClsCd") == scwin.EDI_SND_CLS_CD_SND_COMPLETE) {
            ds_resultsCopinoIn2.setCellData(0, "docStsCls", scwin.EDI_DOC_STS_CLS_CHG);
        }

        if (ds_resultsCopinoIn2.getCellData(0, "temperCls") != "") {
            if (ed_frzTemper2.getValue().trim() == null || ed_frzTemper2.getValue().trim() == "") {
                ds_resultsCopinoIn2.setCellData(0, "temperCls", scwin.EDI_TEMPER_CLS_DRY);
            } else {
                ds_resultsCopinoIn2.setCellData(0, "temperCls", scwin.EDI_TEMPER_CLS_CEL);
            }
        } else {
            ds_resultsCopinoIn2.setCellData(0, "temperCls", "");
        }

        scwin.hid_crryinoutDtmMint2 = ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue();
        ds_resultsCopinoIn2.setCellData(0, "setGauceJobType", 2);
        ds_resultsCopinoIn2.setCellData(0, "emcTransCoId", "DBEXC050");
        ds_resultsCopinoIn2.setCellData(0, "dpctTransCoId", "DBEXC050");
    }

    scwin.hid_crryinoutDtmMint2 = ica_crryinoutDt2.getValue() + ed_crryinoutHh2.getValue();

    // TODO: chk_crryOutCopino, chk_crryInCopino checked 상태에 따른 cntrNo check digit 검증
    if (!$c.gus.cfIsNull(ed_cntrNo1.getValue()) && ed_cntrNo1.getValue() != "") {
        if (!$c.gus.cf_CheckCntrNo(ed_cntrNo1.getValue())) {
            await $c.gus.cfAlertMsg("유효한 컨테이너번호가 아닙니다");
        }
    }
    if (!$c.gus.cfIsNull(ed_cntrNo2.getValue()) && ed_cntrNo2.getValue() != "") {
        if (!$c.gus.cf_CheckCntrNo(ed_cntrNo2.getValue())) {
            await $c.gus.cfAlertMsg("유효한 컨테이너번호가 아닙니다");
        }
    }

    // TODO: chk_crryInCopino, chk_crryOutCopino 둘 다 false 체크
    let chk = await $c.win.confirm("저장하시겠습니까?");
    if (chk) {
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_rtnValue = function() {
    $c.win.closePopup(scwin.arrRtnVal);
};

scwin.f_WinClose = function() {
    scwin.arrRtnVal[0] = "N/A";
    $c.win.closePopup(scwin.arrRtnVal);
};

scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    let pWhere;
    let pTitle;

    switch (disGubun) {
    case 0:
        pWhere = ",,,," + scwin.YN_YES;
        pTitle = "수신처(반출),수신처코드,수신처명";
        rtnList = $c.gus.cfCommonPopUp('retrieveWrkPlInfoEdi_tpro', pCode.trim(), pName.trim(), pClose, null, null, null, null, pWhere, null, null, null, null, null, pAllSearch, pTitle);
        $c.gus.cfSetReturnValue(rtnList, ed_transDstFrom1, ed_transDstFromNm1, [scwin.hid_transDstFromWrkPlCd1]);

        if (!$c.gus.cfIsNull(ed_transDstFrom1.getValue())) {
            scwin.hid_startPoint1 = ed_transDstFrom1.getValue();
            if (ed_transDstFrom1.getValue() == "6P42") {
                ed_mchtCd1.setMandatory(true);
                ed_cntrNo1.setMandatory(false);
                ed_cntrNo1.setValue("");
            } else if (ed_transDstFrom1.getValue() == "6P14" || ed_transDstFrom1.getValue() == "6P12") {
                ed_cntrNo1.setMandatory(true);
                ed_cntrNo1.setValue("ZZZZ1234567");
            } else {
                ed_cntrNo1.setMandatory(true);
            }
            if (ed_transDstFrom1.getValue() == "6P13") {
                acb_chassisPosInfo1.setMandatory(true);
            } else {
                acb_chassisPosInfo1.setMandatory(false);
            }
        }

        if (!$c.gus.cfIsNull(scwin.hid_transDstFromWrkPlCd1)) {
