scwin.ds_resultsCopinoOut_onloadcompleted = async function(e) {
    let rowCnt = ds_resultsCopinoOut.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }
    for (let i = 0; i < ds_resultsCopinoOut.getRowCount(); i++) {
        let sndDtVal = ds_resultsCopinoOut.getCellData(0, "sndDt");
        let sndHhVal = ds_resultsCopinoOut.getCellData(0, "sndHh");
        let sndDtHhText = (sndDtVal == "" ? "" : $c.gus.cfGetFormatStr(sndDtVal, "####/##/##"))
            + " " + (sndHhVal == "" ? "" : $c.gus.cfGetFormatStr(sndHhVal, "##:##:##"));
        // TODO: td_sndDtHh1 텍스트 설정

        let sndClsCdVal = ds_resultsCopinoOut.getCellData(0, "sndClsCd");
        if (sndClsCdVal == scwin.EDI_SND_CLS_CD_SND_COMPLETE) {
            // TODO: td_sndClsCd1 = "전송완료"
        } else if (sndClsCdVal == scwin.EDI_SND_CLS_CD_LATER_SND) {
            // TODO: td_sndClsCd1 = "사후전송"
        } else if (sndClsCdVal == scwin.EDI_SND_CLS_CD_IMPITEM_WARN) {
            // TODO: td_sndClsCd1 = "필수입력오류"
        } else if (sndClsCdVal == scwin.EDI_SND_CLS_CD_SND_WAIT) {
            // TODO: td_sndClsCd1 = "전송대기"
        } else {
            // TODO: td_sndClsCd1 = "미등록"
        }

        if (ds_resultsCopinoOut.getCellData(0, "preInfoGrpClsCd") == scwin.EDI_GRPCD_KYUNGIN_ICD
            && ds_resultsCopinoOut.getCellData(0, "wrkStpCd") != scwin.WRK_STP_CD_RAILROAD) {
            $c.gus.cfDisableObjects([ed_vehclNoFrtcarNo1]);
        }

        let crryinoutDtmMint1Val = ds_resultsCopinoOut.getCellData(0, "crryinoutDtmMint");
        if (crryinoutDtmMint1Val && crryinoutDtmMint1Val.length >= 12) {
            ica_crryinoutDt1.setValue(crryinoutDtmMint1Val.substring(0, 8));
            ed_crryinoutHh1.setValue(crryinoutDtmMint1Val.substring(8, 12));
        }
    }
};

