        for (let i = 0; i < ds_lastCarInOutDTO.getRowCount(); i++) {
            if (ds_lastCarInOutDTO.getCellData(i, "crryinCrryoutCls") == "3" && ed_vehclNoFrtcarNo2.getValue() != "") {
                ed_vehclNoFull2.setValue(ds_lastCarInOutDTO.getCellData(i, "vehclNoFull"));
            }
        }
    }
};

scwin.ed_frzTemper2_onblur = async function(e) {
    if (!(await $c.gus.cfValidate([ed_frzTemper2]))) {
        ed_frzTemper2.setValue("");
    } else {
        if (scwin.hid_sizTyp2 && (scwin.hid_sizTyp2.substr(2, 2) == "RF" || scwin.hid_sizTyp2.substr(2, 2) == "RH")) {
            if (ed_frzTemper2.getValue() == "") {
                scwin.hid_temperCls2 = "DRY";
                acb_temperCls2.setValue("DRY");
            } else {
                scwin.hid_temperCls2 = "CEL";
                acb_temperCls2.setValue("CEL");
            }
        }
    }
};

scwin.acb_expimpClsCd1_onchange = async function(e) {
    let v_expimpClsCd = acb_expimpClsCd1.getValue();
    if (v_expimpClsCd == "I") {
        ed_bookingNo1.setReadOnly(true);
        ed_blNo1.setReadOnly(false);
        $c.gus.cfDisableObjects([ed_bookingNo1]);
        ed_blNo1.setDisabled(false);
        ed_bookingNo1.setValue("");
    } else if (v_expimpClsCd == "E") {
        ed_bookingNo1.setReadOnly(false);
        ed_blNo1.setReadOnly(true);
        ed_bookingNo1.setDisabled(false);
        $c.gus.cfDisableObjects([ed_blNo1]);
        ed_blNo1.setValue("");
    }
};

scwin.acb_fullEmptyClsCd1_onchange = async function(e) {
    if (ds_resultsCopinoOut.getRowCount() > 0) {
        let v_fullEmptyClsCd = acb_fullEmptyClsCd1.getValue();
        if (v_fullEmptyClsCd == "4") {
            ed_sealNo1.setValue(" ");
            ed_sealNo1.setReadOnly(true);
            $c.gus.cfDisableObjects([ed_sealNo1]);
        } else if (v_fullEmptyClsCd == "5") {
            ed_sealNo1.setReadOnly(false);
            $c.gus.cfEnableObjects([ed_sealNo1]);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["E/F 구분"]);
            ed_sealNo1.setReadOnly(true);
            $c.gus.cfDisableObjects([ed_sealNo1]);
        }
    }
};

scwin.acb_expimpClsCd2_onchange = async function(e) {
    let v_expimpClsCd = acb_expimpClsCd2.getValue();
    if (v_expimpClsCd == "I") {
        ed_bookingNo2.setReadOnly(true);
        ed_blNo2.setReadOnly(false);
        $c.gus.cfDisableObjects([ed_bookingNo2]);
        ed_blNo2.setDisabled(false);
    } else if (v_expimpClsCd == "E") {
        ed_bookingNo2.setReadOnly(false);
        ed_blNo2.setReadOnly(true);
        ed_blNo2.setValue("");
        $c.gus.cfDisableObjects([ed_blNo2]);
        ed_bookingNo2.setDisabled(false);
    }
};

scwin.acb_fullEmptyClsCd2_onchange = async function(e) {
    if (ds_resultsCopinoIn.getRowCount() > 0) {
        let v_fullEmptyClsCd2 = acb_fullEmptyClsCd2.getValue();
        if (v_fullEmptyClsCd2 == "4") {
            ed_sealNo2.setValue("");
            ed_totWt2.setMandatory(false);
            $c.gus.cfDisableObjects([ed_sealNo2]);
        } else if (v_fullEmptyClsCd2 == "5") {
            ed_sealNo2.setReadOnly(false);
            $c.gus.cfEnableObjects([ed_sealNo2]);
            ed_totWt2.setMandatory(true);
        } else {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["E/F 구분"]);
            ed_totWt2.setMandatory(false);
            $c.gus.cfDisableObjects([ed_sealNo2]);
        }
    }
    $c.gus.cfRefreshMandSign();
};

scwin.acb_temperCls2_onchange = function(e) {
    let val = acb_temperCls2.getValue();
    if (val == "DRY" || val == "FAH") {
        ed_frzTemper2.setValue("");
        $c.gus.cfDisableObjects([ed_frzTemper2]);
    } else {
        ed_frzTemper2.setValue("");
        $c.gus.cfEnableObjects([ed_frzTemper2]);
    }
};

scwin.acb_tsCls1_onchange = function(e) {
    let v_tsCls1 = acb_tsCls1.getValue();
    if (v_tsCls1 == "14") {
        chk_out_bondTransYn.setMandatory(true);
        ed_bondYardCd.setMandatory(true);
        txt_bondYardNm.setMandatory(true);
    } else {
        chk_out_bondTransYn.setMandatory(false);
        ed_bondYardCd.setMandatory(false);
        txt_bondYardNm.setMandatory(false);
    }
    $c.gus.cfRefreshMandSign();
};

scwin.acb_tsCls2_onchange = function(e) {
    let v_tsCls2 = acb_tsCls2.getValue();
    if (v_tsCls2 == "14") {
        chk_in_bondTransYn.setMandatory(true);
    } else {
        chk_in_bondTransYn.setMandatory(false);
    }
    $c.gus.cfRefreshMandSign();
};

